// sumAbsAndDetail returns the sum of absolute values of non-zero elements
// and optionally a human-readable detail string (label-prefixed if non-empty).
// Returns an error when the sum is zero.
func sumAbsAndDetail(nums []int, label string, verbose bool) (int, string, error) {
	var total int
	var detail string
	for _, n := range nums {
		if n > 0 {
			total += n
			if verbose {
				detail += fmt.Sprintf("%d,", n)
			}
		} else if n < 0 {
			total -= n
			if verbose {
				detail += fmt.Sprintf("(%d),", n)
			}
		}
	}
	if total == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}
	if label != "" {
		detail = label + ": " + detail
	}
	return total, detail, nil
}

